// --- All 31 languages filled; t() falls back through EN / key. ---

const DICTIONARIES: Record<LangCode, Translations> = {
  en: EN,
  es: ES,
  fr: FR,
  de: DE,
  pt: PT,
  it: IT,
  hr: HR,
  zh: ZH,
  hi: HI,
  ar: AR,
  bn: BN,
  ru: RU,
  id: ID,
  mr: MR,
  ja: JA,
  te: TE,
  tr: TR,
  ta: TA,
  vi: VI,
  ko: KO,
  ur: UR,
  th: TH,
  pl: PL,
  nl: NL,
  el: EL,
  uk: UK,
  ro: RO,
  xh: XH,
  sw: SW,
  hu: HU,
  sv: SV,
}

export function t(key: TranslationKeys, lang: LangCode): string {
  return DICTIONARIES[lang]?.[key] ?? EN[key] ?? key
}

// Sprint 8 — cascade for admin-editable free-text blocks (disclaimer_text,
// instructions_text). Resolution order:
//   1. translations[lang]        (translated text for the user's language)
//   2. source (if lang === source_language, or as last non-i18n fallback)
//   3. null (caller shows the i18n default)
export function pickBrandingText(
  source: string | undefined,
  sourceLanguage: string | undefined,
  translations: Record<string, string> | undefined,
  lang: LangCode,
): string | null {
  const src = (source || '').trim()
  if (!src) return null
  const srcLang = (sourceLanguage || 'en').trim() || 'en'
  const translated = (translations?.[lang] || '').trim()
  if (translated) return translated
  if (lang === srcLang) return src
  // No translation for this language — fall back to source so the user sees
  // *something* rather than the i18n default, which may have a different
  // phrasing than the admin's override. The alternative of returning null
  // would swap mid-chat text, which is more confusing.
  return src
}
